mapper.select:
SELECT	*
FROM s_menu_manager
WHERE 	MN_DEL_YN		=		'N'
AND		MN_USE_YN		=		'Y'

AND		MN_URL			=		#{MN_URL}


AND		MN_KEYNO			=	#{MN_HOMEDIV_C}

SELECT A.* , CASE MN_PAGEDIV_C WHEN 'SC_EANHU' THEN '단일 페이지' WHEN 'SC_TFOVO' THEN '게시판' WHEN 'SC_HFAIU' THEN '링크' WHEN 'SC_QXCFB' THEN '소메뉴' WHEN 'SC_VUWAQ' THEN '개발자페이지' WHEN 'SC_DEFGR' THEN '관광페이지' END MN_PAGEDIV_NAME , (SELECT COUNT(*) FROM s_menu_manager WHERE A.MN_KEYNO = MN_MAINKEY AND MN_DEL_YN = 'N'
AND MN_PAGEDIV_C IN
#{pageDiv}
) MN_CHILD_CNT , (SELECT COUNT(*) FROM s_menu_manager WHERE MN_URL LIKE (A.MN_URL||'%.do') AND MN_PAGEDIV_C = 'SC_EANHU') MN_PAGEVIEW_CNT
, ( SELECT LISTAGG(UIR_KEYNO, ',') WITHIN GROUP (ORDER BY UIR_KEYNO) FROM u_userinfo_authority_roll WHERE MN_KEYNO = A.MN_KEYNO AND UIA_KEYNO = #{UIA_KEYNO} ) MN_ROLES , ( SELECT LISTAGG(UIR_KEYNO, ',') WITHIN GROUP (ORDER BY UIR_KEYNO) FROM u_userinfo_authority_roll WHERE MN_KEYNO = A.MN_KEYNO AND UIA_KEYNO = #{UIA_MAINKEY} ) MN_ROLES_MAIN
FROM s_menu_manager A WHERE MN_DEL_YN = 'N' AND MN_HOMEDIV_C = #{HM_MN_HOMEDIV_C}
AND MN_PAGEDIV_C IN
#{pageDiv}
ORDER BY MN_LEV, MN_ORDER

SELECT DISTINCT A.* , CASE MN_PAGEDIV_C WHEN 'SC_EANHU' THEN '단일 페이지' WHEN 'SC_TFOVO' THEN '게시판' WHEN 'SC_HFAIU' THEN '링크' WHEN 'SC_QXCFB' THEN '소메뉴' WHEN 'SC_VUWAQ' THEN '개발자페이지' WHEN 'SC_DEFGR' THEN '관광페이지' END MN_PAGEDIV_NAME , (SELECT COUNT(*) FROM s_menu_manager
WHERE A.MN_KEYNO = MN_MAINKEY AND MN_DEL_YN = 'N'
AND MN_PAGEDIV_C IN
#{pageDiv}
) MN_CHILD_CNT , (SELECT COUNT(*) FROM s_menu_manager SMM2
WHERE MN_URL LIKE CONCAT(A.MN_URL,'%.do') AND SMM2.MN_PAGEDIV_C = 'SC_EANHU'
) MN_PAGEVIEW_CNT
FROM s_menu_manager A
LEFT JOIN u_userinfo_authority_roll UAR ON A.MN_KEYNO = UAR.MN_KEYNO
WHERE MN_DEL_YN = 'N' AND MN_HOMEDIV_C = #{HM_MN_HOMEDIV_C}
AND MN_PAGEDIV_C IN
#{pageDiv}
AND ( UAR.UIA_KEYNO = #{UIA_KEYNO} OR (MN_LEV >= 1 AND SUBSTR(MN_URL, INSTR(MN_URL,'/' , 2) + 1, 6) LIKE 'member') )
ORDER BY MN_LEV, MN_ORDER

SELECT * FROM s_menu_manager WHERE MN_DEL_YN = 'N' AND MN_USE_YN = 'Y'
AND MN_SHOW_YN = #{MN_SHOW_YN}
AND MN_HOMEDIV_C = #{MN_HOMEDIV_C} ORDER BY MN_ORDER

SELECT (SELECT MVD_KEYNO FROM s_menu_view_data WHERE MVD_MN_KEYNO = A.MN_KEYNO ) MVD_KEYNO , A.* , B.* , CASE MN_KEYNO WHEN #{MN_KEYNO} THEN '2' WHEN #{MN_HOMEPAGE_REP} THEN '1' ELSE '0' END ADMIN_PRIORITY FROM s_menu_manager A, S_HOME_MANAGER B WHERE A.MN_HOMEDIV_C = B.HM_MN_HOMEDIV_C AND MN_DEL_YN = #{MN_DEL_YN} AND HM_USE_YN = 'Y'
AND MN_HOMEDIV_C = #{MN_HOMEDIV_C}
AND MN_KEYNO != #{MN_KEYNO}
AND REPLACE(MN_MAINKEY, ' ' ,'') IS NULL
AND MN_MAINKEY = #{MN_MAINKEY}
ORDER BY ADMIN_PRIORITY DESC, MN_ORDER

SELECT COUNT(*) FROM s_menu_manager A WHERE MN_DEL_YN = 'N'
AND MN_HOMEDIV_C = #{MN_HOMEDIV_C}
AND MN_MAINKEY = #{MN_MAINKEY}
AND MN_LEV = 0
ORDER BY MN_ORDER

SELECT A.* , MM.MN_NAME HIGH_MN_NAME , MM.MN_DATA1 AS MN_MAIN_DATA1 , FS.FS_FOLDER||FS.FS_CHANGENM||'.'||FS.FS_EXT AS IMG_PATH , DM.DN_HOMEDIV_C PAGE_HOMEDIV_C , DU.DU_KEYNO PAGE_KEYNO , DU.DU_NAME PAGE_NAME , DU.DU_TEL PAGE_TEL , DM.DN_NAME PAGE_DEPARTMENT , HM.HM_SESSION sessionTime FROM s_menu_manager A LEFT JOIN s_common_file_sub FS ON A.MN_QR_KEYNO = FS.FS_KEYNO LEFT JOIN s_menu_manager MM ON A.MN_MAINKEY = MM.MN_KEYNO LEFT JOIN t_department_user_manager DU ON A.MN_DU_KEYNO = DU.DU_KEYNO LEFT JOIN t_department_manager DM ON DU.DU_DN_KEYNO = DM.DN_KEYNO LEFT JOIN s_home_manager HM ON A.MN_HOMEDIV_C = HM.HM_MN_HOMEDIV_C WHERE A.MN_DEL_YN = 'N'
AND A.MN_KEYNO = #{MN_KEYNO}
AND ( A.MN_URL = #{MN_URL} OR A.MN_FORWARD_URL = #{MN_URL} ) AND A.MN_PAGEDIV_C != 'SC_HFAIU'

SELECT	A.*
FROM s_menu_manager A
WHERE 	A.MN_DEL_YN 		=		'N'
AND     (  
			A.MN_URL			=	#{MN_URL} 
			OR  
			A.MN_FORWARD_URL    =  	#{MN_URL} 
		)


SELECT 	COUNT(*)
FROM s_menu_manager 
WHERE 	MN_DEL_YN 		=	'N'
AND		( 
			MN_URL 		=	#{MN_URL} 
			OR 
			MN_FORWARD_URL = #{MN_URL} 
		)
AND		MN_PAGEDIV_C 	!=	#{MN_PAGEDIV_C}
AND		MN_KEYNO		!=	#{MN_KEYNO}

