UPDATE s_menu_manager A SET MN_ORDER = ( CASE WHEN MN_KEYNO = #{MN_KEYNO} THEN #{MN_ORDER}
WHEN MN_ORDER >= #{MN_ORDER} AND MN_ORDER <= #{MN_ORDER_BEFORE} THEN MN_ORDER + 1 WHEN MN_ORDER >= #{MN_ORDER_BEFORE} AND MN_ORDER <= #{MN_ORDER} THEN MN_ORDER - 1
ELSE MN_ORDER END ) WHERE MN_MAINKEY = #{MN_MAINKEY} AND MN_DEL_YN = 'N'

		UPDATE s_menu_manager
     SET MN_ORDER = MN_ORDER - 1
     WHERE MN_MAINKEY = #{MN_MAINKEY}
     AND	  MN_ORDER >= #{MN_ORDER}
     AND   MN_DEL_YN = 'N'

