SELECT MN_NAME AS MN_SUB_NAME ,(SELECT MN_NAME FROM s_menu_manager WHERE MN_KEYNO = MN.MN_MAINKEY)||' - '||MN_NAME AS MN_NAME ,(SELECT MN_NAME FROM s_menu_manager WHERE MN_KEYNO = MN.MN_MAINKEY) AS MN_MAIN_NAME , MN_KEYNO , MN_BT_KEYNO , BT.BT_CODEKEY AS BTCODEKEY , BT.BT_TYPE_NAME , ( SELECT LISTAGG(C.UIA_NAME,',') WITHIN GROUP (ORDER BY C.UIA_NAME) FROM u_userinfo_authority_roll B, U_USERINFO_AUTHORITY C WHERE B.UIA_KEYNO = C.UIA_KEYNO AND B.MN_KEYNO = MN.MN_KEYNO AND B.UIR_KEYNO = 'UIR_0000000015' ) AUTHLIST FROM s_menu_manager MN, B_BOARD_TYPE BT WHERE MN.MN_BT_KEYNO = BT.BT_KEYNO
AND MN.MN_HOMEDIV_C = #{MN_HOMEDIV_C}
AND BT.BT_USE_YN = 'Y' AND MN.MN_DEL_YN = 'N' AND MN.MN_USE_YN = 'Y' AND MN.MN_PAGEDIV_C = 'SC_TFOVO' ORDER BY MN_KEYNO

