mapper.sql:
FROM( SELECT AA.* , ROW_NUMBER() OVER (
ORDER BY COUNT ${sortDirect}
ORDER BY SMT_SUBJECT ${sortDirect}
ORDER BY SMT_UI_NAME ${sortDirect}
ORDER BY SMT_REGDT ${sortDirect}
ORDER BY SMT_KEYNO DESC
) RNUM FROM( SELECT SMT_KEYNO , ROWNUM COUNT , TO_CHAR(SMT_REGDT,'YYYY-MM-dd') SMT_REGDT , NVL(U.UI_REP_NAME,SMT_REGNM) SMT_UI_NAME , SMT_SUBJECT FROM s_menu_template B LEFT JOIN u_userinfo U ON B.SMT_REGNM = U.UI_KEYNO WHERE SMT_DELYN = 'N' )AA WHERE 1=1
AND COUNT LIKE '%' || #{item.searchKeyword} || '%'
AND SMT_SUBJECT LIKE '%' || #{item.searchKeyword} || '%'
AND SMT_UI_NAME LIKE '%' || #{item.searchKeyword} || '%'
AND SMT_REGDT LIKE '%' || #{item.searchKeyword} || '%'
AND ( COUNT LIKE '%' || #{item.searchKeyword} || '%' OR SMT_SUBJECT LIKE '%' || #{item.searchKeyword} || '%' OR SMT_UI_NAME LIKE '%' || #{item.searchKeyword} || '%' OR SMT_REGDT LIKE '%' || #{item.searchKeyword} || '%' )
) AAA

mapper.select:
	SELECT	*


	 	WHERE 1=1
 		AND RNUM BETWEEN #{firstIndex}+1 AND #{recordCountPerPage}

