INSERT ALL

INTO S_MENU_MANAGER(
	 MN_KEYNO
	,MN_NAME
	,MN_ENG_NAME
	,MN_DEP
	,MN_COLOR
	,MN_DATA1
	,MN_DATA2
	,MN_DATA3
	,MN_HOMEDIV_C
	,MN_PAGEDIV_C
	,MN_BT_KEYNO
	,MN_TOURKEY
	,MN_URL
	,MN_FORWARD_URL
	,MN_MAINKEY
	,MN_ORDER
	,MN_LEV
	,MN_ICON_CSS
	,MN_RESEARCH
	,MN_QRCODE
	,MN_MANAGER
	,MN_USE_YN
	,MN_SHOW_YN
	,MN_DEL_YN
	,MN_REGDT
	,MN_REGNM
	,MN_QR_KEYNO
	,MN_MANAGER_DEP
	,MN_MANAGER_TEL
	,MN_DU_KEYNO
	,MN_GONGNULI_TYPE
	,MN_GONGNULI_YN
	,MN_EMAIL
	,MN_NEWLINK
	,MN_META_DESC
	,MN_META_KEYWORD
	,MN_CHANGE_FREQ
	,MN_PRIORITY
	)
VALUES
(
	 #{item.MN_KEYNO}
	,#{item.MN_NAME}
	,#{item.MN_ENG_NAME}
	,#{item.MN_DEP}
	,#{item.MN_COLOR}
	,#{item.MN_DATA1}
	,#{item.MN_DATA2}
	,#{item.MN_DATA3}
	,#{item.MN_HOMEDIV_C}
	,#{item.MN_PAGEDIV_C}
	,#{item.MN_BT_KEYNO}
	,#{item.MN_TOURKEY}
	,#{item.MN_URL}
	,#{item.MN_FORWARD_URL}
	,#{item.MN_MAINKEY}
	,#{item.MN_ORDER}
	,#{item.MN_LEV}
	,#{item.MN_ICON_CSS}
	,#{item.MN_RESEARCH}
	,#{item.MN_QRCODE}
	,#{item.MN_MANAGER}
	,#{item.MN_USE_YN}
	,#{item.MN_SHOW_YN}
	,'N'
	,SYSDATE
	,#{item.MN_REGNM}
	,#{item.MN_QR_KEYNO}
	,#{item.MN_MANAGER_DEP}
	,#{item.MN_MANAGER_TEL}
	,#{item.MN_DU_KEYNO}
	,#{item.MN_GONGNULI_TYPE}
	,#{item.MN_GONGNULI_YN}
	,#{item.MN_EMAIL}
	,#{item.MN_NEWLINK}
	,#{item.MN_META_DESC}
	,#{item.MN_META_KEYWORD}
	,#{item.MN_CHANGE_FREQ}
	,#{item.MN_PRIORITY}
)

